    @Test
    @DisplayName("decideAction: returns non-null in a normal game state")
    void decideAction_returnsNonNull() {
        GameState state = buildDefaultState(player);
        assertNotNull(strategy.decideAction(state, player));
    }

    @Test
    @DisplayName("decideAction: returns PURCHASE_CARD when player can afford a visible card")
    void decideAction_prefersPurchaseWhenAffordable() {
        GameState state = buildStateWithFreeCards(player);
        AIAction action = strategy.decideAction(state, player);
        assertEquals(ActionType.PURCHASE_CARD, action.getActionType());
    }

    @Test
    @DisplayName("decideAction: PURCHASE_CARD action carries a non-null targetCard")
    void decideAction_purchaseActionHasTargetCard() {
        GameState state = buildStateWithFreeCards(player);
        AIAction action = strategy.decideAction(state, player);
        assertNotNull(action.getTargetCard());
    }

    @Test
    @DisplayName("decideAction: PURCHASE_CARD from market has fromReserved=false")
    void decideAction_purchaseFromMarketIsNotFromReserved() {
        GameState state = buildStateWithFreeCards(player);
        AIAction action = strategy.decideAction(state, player);
        assertFalse(action.isFromReserved());
    }

    @Test
    @DisplayName("decideAction: returns PURCHASE_CARD fromReserved=true when only reserved card is affordable")
    void decideAction_purchaseFromReservedWhenOnlyReservedIsAffordable() {
        // Visible cards are all very expensive; reserved card has zero cost.
        // Use WHITE bonus so discount utility is non-zero (expensive cards cost WHITE).
        Card freeReserved = buildFreeCard(2, 3, GemColor.WHITE);
        player.addReservedCard(freeReserved);
        GameState state = buildStateWithExpensiveCards(player);

        AIAction action = strategy.decideAction(state, player);

        assertEquals(ActionType.PURCHASE_CARD, action.getActionType());
        assertTrue(action.isFromReserved());
        assertSame(freeReserved, action.getTargetCard());
    }

    @Test
    @DisplayName("decideAction: returns a TAKE action when no card is affordable")
    void decideAction_returnsTakeActionWhenNothingAffordable() {
        GameState state = buildStateWithExpensiveCards(player);
        AIAction action = strategy.decideAction(state, player);
        assertNotNull(action);
        assertTrue(
            action.getActionType() == ActionType.TAKE_THREE_DIFFERENT ||
            action.getActionType() == ActionType.TAKE_TWO_SAME,
            "Expected a gem-take action but got: " + action.getActionType()
        );
    }

    @Test
    @DisplayName("decideAction: TAKE action carries a non-null gemSelection with at least 1 gem")
    void decideAction_takeActionHasGemSelection() {
        GameState state = buildStateWithExpensiveCards(player);
        AIAction action = strategy.decideAction(state, player);
        assertNotNull(action.getGemSelection());
        assertTrue(action.getGemSelection().getTotalCount() > 0);
    }

    @Test
    @DisplayName("decideAction: TAKE_THREE_DIFFERENT gemSelection has exactly 3 gems")
    void decideAction_takeThreeDifferentHasExactlyThreeGems() {
        GameState state = buildStateWithExpensiveCards(player);
        AIAction action = strategy.decideAction(state, player);
        if (action.getActionType() == ActionType.TAKE_THREE_DIFFERENT) {
            assertEquals(3, action.getGemSelection().getTotalCount());
        }
    }

    @Test
    @DisplayName("decideAction: does not return RESERVE_CARD when player already has 3 reserved cards")
    void decideAction_doesNotReserveAtMaxCapacity() {
        player.addReservedCard(buildExpensiveCard(1));
        player.addReservedCard(buildExpensiveCard(1));
        player.addReservedCard(buildExpensiveCard(1));
        GameState state = buildStateWithExpensiveCards(player);

        AIAction action = strategy.decideAction(state, player);

        assertNotNull(action);
        assertNotEquals(ActionType.RESERVE_CARD, action.getActionType());
    }

    @Test
    @DisplayName("decideAction: prefers PURCHASE over RESERVE for same visible card (full score vs 0.7x)")
    void decideAction_prefersPurchaseOverReserveForSameCard() {
        // Free cards are affordable → purchase at full score beats reserve at 0.7x
        GameState state = buildStateWithFreeCards(player);
        AIAction action = strategy.decideAction(state, player);
        assertEquals(ActionType.PURCHASE_CARD, action.getActionType());
    }

    // =========================================================
    // chooseNoble
