    @Test
    @DisplayName("chooseNoble: returned noble is always a member of the claimable list")
    void chooseNoble_returnedNobleIsInClaimableList() {
        Noble noble1 = buildSingleColorNoble(1, GemColor.WHITE, 3);
        Noble noble2 = buildSingleColorNoble(2, GemColor.RED, 3);
        List<Noble> claimable = new ArrayList<>(List.of(noble1, noble2));
        GameState state = buildStateWithNobles(player, new ArrayList<>(claimable));

        Noble chosen = strategy.chooseNoble(claimable, state, player);

        assertTrue(claimable.contains(chosen));
    }

    @Test
    @DisplayName("chooseNoble: returns non-null for any non-empty claimable list")
    void chooseNoble_returnsNonNullForNonEmptyList() {
        Noble noble = buildSingleColorNoble(1, GemColor.BLUE, 3);
        List<Noble> claimable = List.of(noble);
        GameState state = buildStateWithNobles(player, new ArrayList<>(claimable));

        assertNotNull(strategy.chooseNoble(claimable, state, player));
    }

    @Test
    @DisplayName("chooseNoble: blocking strategy — picks noble opponent is closest to claiming")
    void chooseNoble_picksNobleOpponentIsClosestTo() {
        // Opponent has 2 WHITE bonus cards (needs 3 for noble1) → deficit=1 → score=1/(1+1)=0.5
        // Opponent has 0 RED bonus cards (needs 3 for noble2)  → deficit=3 → score=1/(3+1)=0.25
        // AI should pick noble1 to block the opponent
        Player opponent = new Player("Opponent", 1);
        Map<GemColor, Integer> whiteCost = new EnumMap<>(GemColor.class);
        whiteCost.put(GemColor.WHITE, 1);
        opponent.addCard(new Card(1, 0, GemColor.WHITE, new Cost(whiteCost)));
        opponent.addCard(new Card(1, 0, GemColor.WHITE, new Cost(whiteCost)));

        Noble noble1 = buildSingleColorNoble(1, GemColor.WHITE, 3);
        Noble noble2 = buildSingleColorNoble(2, GemColor.RED,   3);
        List<Noble> claimable = new ArrayList<>(List.of(noble1, noble2));

        CardMarket market = new CardMarket(buildCardList(1, 20), buildCardList(2, 20), buildCardList(3, 20));
        GameState state = new GameState(
                List.of(player, opponent), market, fullBank(), new ArrayList<>(claimable), 15);

        Noble chosen = strategy.chooseNoble(claimable, state, player);
        assertSame(noble1, chosen);
    }

    @Test
    @DisplayName("chooseNoble: returns first-encountered noble when blocking scores tie (no opponents)")
    void chooseNoble_returnsFirstOnTie() {
        // Single-player game → no opponents → all blocking scores are 0.0
        // Strict '>' means first-encountered (noble1) wins the tie
        Noble noble1 = buildSingleColorNoble(1, GemColor.WHITE, 3);
        Noble noble2 = buildSingleColorNoble(2, GemColor.RED, 3);
        List<Noble> claimable = new ArrayList<>(List.of(noble1, noble2));
        GameState state = buildStateWithNobles(player, new ArrayList<>(claimable));

        Noble chosen = strategy.chooseNoble(claimable, state, player);
        assertSame(noble1, chosen);
    }

    // =========================================================
    // chooseGemsToReturn
